  ('locality-6f0ba476-moex-00536', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '假設兩人經濟體系有邊沁（Bentham）的社會福利函數，每人有相同的偏好，但所得不同，偏好只 和所得有關，總所得固定不變。關於最適租稅的設計，下列何者正確？', '["應採用較累進的所得稅制進行所得重分配", "應只對其中一人課稅，把所得全部移轉給另一人", "應採對任何所得水準皆課單一稅率的所得稅制", "應對兩人沒有消費的商品課稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "2255401c3abb", "answer_pdf_sha1": "d17af0bc0582", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00537', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '承上題，假設只有兩人，高所得者的邊際稅率為多少？', '["0%", "50%", "100%", "20%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "2255401c3abb", "answer_pdf_sha1": "d17af0bc0582", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00538', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '利息收入須納入所得申報所得稅，但利息費用不可列為扣除項。在此一稅制下，調高所得稅率對 儲蓄具有何種影響？', '["若原為儲蓄者，其儲蓄將減少", "若原為借貸者，其借貸將減少", "若原為借貸者，其借貸將增加", "若原為儲蓄者，需視替代效果與所得效果而定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "2255401c3abb", "answer_pdf_sha1": "d17af0bc0582", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00539', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '在小型開放的經濟體系下，若對國內儲蓄的利息所得課稅，則對投資的資金成本及儲蓄者的稅後 利息所得有何影響？', '["資金成本不變，稅後利息所得減少", "資金成本上升，稅後利息所得減少", "資金成本上升，稅後利息所得不變", "資金成本不變，稅後利息所得不變"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "2255401c3abb", "answer_pdf_sha1": "d17af0bc0582", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00540', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '在T =-a+tY 的單一稅率所得稅（flatrateincometax）下（其中T 為個人i的所得稅稅額，a為 i i i 定額補貼，t為單一所得稅稅率，Y 為個人i的所得額），下列敘述何者正確？ i', '["此制度下，所有納稅人適用之平均稅率相同", "此制度下，所有納稅人適用之邊際稅率相同", "此制度不具備累進性", "一般認為此制度較符合人們要求公平的概念，且對工作誘因沒有影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "2255401c3abb", "answer_pdf_sha1": "d17af0bc0582", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00541', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '根據加速模型（acceleratormodel），公司所得稅若影響下列何者，將使實體投資改變？', '["工資水準", "產出水準", "消費水準", "資本價格"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "2255401c3abb", "answer_pdf_sha1": "d17af0bc0582", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00542', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '在其他條件不變下，證券交易所得免課個人所得稅，公司股東保留盈餘的誘因會傾向於：', '["減少", "無關", "增加", "不變"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "2255401c3abb", "answer_pdf_sha1": "d17af0bc0582", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00543', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '根據新古典模型，若資本財供給曲線分別為正斜率與水平，下列對租稅扣抵之投資增加效果的敘 述，何者正確？', '["正斜率供給曲線之效果大於水平供給曲線之效果", "正斜率供給曲線之效果小於水平供給曲線之效果", "兩者效果相同", "兩者無法比較"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "2255401c3abb", "answer_pdf_sha1": "d17af0bc0582", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00544', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '在兩期生命循環週期模型中，甲與乙在第一期皆有勞動所得$1,000，第二期則無所得，利率（折 現率）為10%，兩期的所得稅稅率皆為50%。甲在第一期消費所有的稅後所得，乙則全部存入銀 行以供第二期消費。若和兩期稅率皆為50%的消費稅比較，下列何者錯誤？', '["若課徵所得稅，則甲與乙第一期繳納的所得稅一樣多", "若課徵消費稅，則甲第一期繳納的消費稅較乙為多", "若課徵所得稅，則甲與乙負擔相同的終身所得稅稅負", "若課徵消費稅，則甲與乙負擔相同的終身消費稅稅負"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "2255401c3abb", "answer_pdf_sha1": "d17af0bc0582", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
